import { useState, useEffect } from "react";
import axios from "../axiosConfig";
import { useCookies } from "react-cookie";
import { useNavigate } from "react-router-dom";

export function UserDashboard() {
    const [videos, setVideos] = useState([]);
    const [cookies, , removeCookie] = useCookies(['user-id']);
    const navigate = useNavigate();

    function LoadVideos() {
        axios.get('/get-videos')
            .then(response => {
                if (Array.isArray(response.data)) {
                    setVideos(response.data);
                } else {
                    setVideos([]);
                    console.warn("Expected an array but got:", response.data);
                }
            })
            .catch(error => {
                console.error("Error fetching videos:", error);
                setVideos([]);
            });
    }

    useEffect(() => {
        LoadVideos();
    }, []);

    function handleSignoutClick() {
        removeCookie('user-id');
        navigate('/user-login');
        window.location.reload();
    }

    return (
        <div>
            <h3>
                {cookies['user-id']} Dashboard - 
                <button onClick={handleSignoutClick} className="btn btn-danger">Signout</button>
            </h3>
            <div className="my-3">
                <select>
                    <option>Select Category</option>
                    <option>HTML</option>
                    <option>React JS</option>
                    <option>Java</option>
                </select>
            </div>
            <main className="d-flex flex-wrap">
                {
                    videos.length > 0 ? (
                        videos.map(video =>
                            <div key={video.VideoId} className="card m-2 p-2" style={{ width: '250px' }}>
                                <div className="card-header" style={{ height: '200px' }}>
                                    <iframe
                                        src={video.Url}
                                        width="100%"
                                        height="200"
                                        title={video.Title}
                                        allowFullScreen
                                    ></iframe>
                                </div>
                                <div className="card-body">{video.Title}</div>
                                <div className="card-footer">
                                    <button className="bi bi-eye btn"> {video.Views}</button>
                                    <button className="bi bi-hand-thumbs-up btn"> {video.Likes}</button>
                                    <button className="bi bi-hand-thumbs-down btn"> {video.Dislikes}</button>
                                </div>
                            </div>
                        )
                    ) : (
                        <p className="text-center text-muted w-100">No videos available.</p>
                    )
                }
            </main>
        </div>
    );
}
